class Solution:
    def numberOfSubstrings(self, s, k):
        n = len(s)
        count = 0
        for i in range(n):
            freq = [0] * 26
            maxf = 0
            for j in range(i, n):
                idx = ord(s[j]) - 97
                freq[idx] += 1
                if freq[idx] > maxf:
                    maxf = freq[idx]
                if maxf >= k:
                    count += 1
        return count

