class Solution:
    def numberOfSubstrings(self, s: str, k: int) -> int:
        n = len(s)

        def at_most(limit):
            if limit < 0:
                return 0
            freq = [0] * 26
            left = 0
            res = 0
            for right in range(n):
                idx = ord(s[right]) - 97
                freq[idx] += 1
                while freq[idx] > limit:
                    freq[ord(s[left]) - 97] -= 1
                    left += 1
                res += right - left + 1
            return res

        total = n * (n + 1) // 2
        return total - at_most(k - 1)

