var numberOfSubstrings = function(s, k) {
    const n = s.length;
    const atMost = (limit) => {
        if (limit < 0) return 0;
        const freq = new Array(26).fill(0);
        let left = 0;
        let res = 0;
        for (let right = 0; right < n; right++) {
            const idx = s.charCodeAt(right) - 97;
            freq[idx]++;
            while (freq[idx] > limit) {
                freq[s.charCodeAt(left) - 97]--;
                left++;
            }
            res += right - left + 1;
        }
        return res;
    };
    const total = n * (n + 1) / 2;
    return total - atMost(k - 1);
};
